import{_ as s,c as a,a1 as n,o as t}from"./chunks/framework.BDxlaA_J.js";const u=JSON.parse('{"title":"Information Gathering using Metasploit","description":"","frontmatter":{},"headers":[],"relativePath":"categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/5-Metasploit-Basics.md","filePath":"categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/5-Metasploit-Basics.md"}'),o={name:"categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/5-Metasploit-Basics.md"};function p(i,e,c,r,l,d){return t(),a("div",null,e[0]||(e[0]=[n(`<h1 id="information-gathering-using-metasploit" tabindex="-1">Information Gathering using Metasploit <a class="header-anchor" href="#information-gathering-using-metasploit" aria-label="Permalink to &quot;Information Gathering using Metasploit&quot;">​</a></h1><p>The Metasploit Framework is a tool that provides information about secuirty vulnerabilities and aids in penetration testing and IDS signature development. <em>Official repository:</em> <a href="https://github.com/rapid7/metasploit-framework" target="_blank" rel="noreferrer">https://github.com/rapid7/metasploit-framework</a></p><p><strong>Metasploit version: 5.0.59-dev</strong></p><p>Metasploit can be used to test the vulnerability of computer systems or to break into remote systems. <strong>This lab will demonstrate extracting information using Metasploit Framework.</strong></p><h2 id="metasploit-overview" tabindex="-1">Metasploit overview: <a class="header-anchor" href="#metasploit-overview" aria-label="Permalink to &quot;Metasploit overview:&quot;">​</a></h2><p>Metasploit Framework is an open-source project that facilitates the task of attackers, exploit and payload writers. A major advantage of the framework is the moduler approach, allowing the combination of any exploit with any payload.</p><h3 id="requirements" tabindex="-1">Requirements: <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements:&quot;">​</a></h3><ul><li>Kali Linux virtual machine.</li></ul><h3 id="objectives" tabindex="-1">Objectives: <a class="header-anchor" href="#objectives" aria-label="Permalink to &quot;Objectives:&quot;">​</a></h3><ul><li>How to identify vulnerabilities and information disclosures.</li><li>Extract accurate information about a network.</li></ul><hr><h2 id="metasploit-setup" tabindex="-1">Metasploit setup <a class="header-anchor" href="#metasploit-setup" aria-label="Permalink to &quot;Metasploit setup&quot;">​</a></h2><p>Log into <strong>Kali Linux</strong> machine and open a <strong>Terminal</strong> window.</p><p>Start PostgreSQL database service to link with Metasploit:</p><p><code>service postgresql start</code></p><p>Now type <code>msfconsole</code> to launch Metasploit.</p><p><code>msfconsole</code></p><p>Check if Metasploit is connected to the database successfully:</p><p><code>db_status</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[*] postgresql selected, no connection</span></span></code></pre></div><p>If you got this message, it means that database did not connected to msf properly. To fix this issue, type <code>exit</code> to quit Metasploit. Then, to initiate the database, type:</p><p><code>msfdb init</code></p><p>Then, restart the postgresql service:</p><p><code>service postgresql restart</code></p><p>Start Metasploit again and run the <code>db_status</code> to check the database status:</p><p><code>msfconsole</code><code>db_status</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[*] Connected to msf. Connection type: postgresql.</span></span></code></pre></div><p>Now the database is connected successfully to the msf.</p><h2 id="find-alive-hosts" tabindex="-1">Find alive hosts <a class="header-anchor" href="#find-alive-hosts" aria-label="Permalink to &quot;Find alive hosts&quot;">​</a></h2><p>I recommend to boot up a couple VMs in your Lab. In my case I fired up:</p><ul><li>Ubuntu Metasploitable</li><li>Windows 7 SP1</li><li>Windows Server 2012 R2</li></ul><p>To scan the subnet, we can use <strong>Nmap</strong>:</p><p><code>nmap -O -oX Test 10.0.2.0/24</code></p><p>Nmap starts scanning the subnet and showing the results on the screen. The <code>-oX Test</code> Nmap command stands for <strong>output in XML</strong> file called <strong>Test</strong>.</p><p>We can import the Nmap results from the database:</p><p><code>db_import Test</code></p><p>To see the hosts and their details discovered by Nmap type:</p><p><code>hosts</code> ... <em>(Check the OS versions, IP and MAC addresses).</em></p><p>I will select the Windows Server 2012, that I scanned to check the services running on this system.</p><p><code>db_nmap -sS -A 10.0.2.28</code></p><p>Nmap starts to footprint the system and list out the OS details.</p><p>The <code>db_nmap</code> start the Nmap scan and the results would than be stored automatically in our database.</p><p>Type <code>services</code> or <code>db_services</code> to get the whole list of the services running on the host.</p><p><code>db_services</code></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/2734644f73fe43d2b99b56a03fb4bab3b01acf20/services-nmap-scan.png" alt="alt text" title="Nmap Services Scan"></p><h2 id="scan-for-open-ports-and-services" tabindex="-1">Scan for open ports and services <a class="header-anchor" href="#scan-for-open-ports-and-services" aria-label="Permalink to &quot;Scan for open ports and services&quot;">​</a></h2><p>Search for <strong>portscan</strong> modules:</p><p><code>search portscan</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>#  Name                                    Disclosure Date  Rank    Check  Description</span></span>
<span class="line"><span>-  ----                                    ---------------  ----    -----  -----------</span></span>
<span class="line"><span>0  auxiliary/scanner/http/wordpress_pingback_access         normal  Yes    Wordpress Pingback Locator</span></span>
<span class="line"><span>1  auxiliary/scanner/natpmp/natpmp_portscan                 normal  Yes    NAT-PMP External Port Scanner</span></span>
<span class="line"><span>2  auxiliary/scanner/portscan/ack                           normal  Yes    TCP ACK Firewall Scanner</span></span>
<span class="line"><span>3  auxiliary/scanner/portscan/ftpbounce                     normal  Yes    FTP Bounce Port Scanner</span></span>
<span class="line"><span>4  auxiliary/scanner/portscan/syn                           normal  Yes    TCP SYN Port Scanner</span></span>
<span class="line"><span>5  auxiliary/scanner/portscan/tcp                           normal  Yes    TCP Port Scanner</span></span>
<span class="line"><span>6  auxiliary/scanner/portscan/xmas                          normal  Yes    TCP &quot;XMas&quot; Port Scanner</span></span>
<span class="line"><span>7  auxiliary/scanner/sap/sap_router_portscanner             normal  No     SAPRouter Port Scanner</span></span></code></pre></div><p>Select the <strong>scanner/portscan/syn</strong>:</p><p><code>use scanner/portscan/syn</code></p><p>Now we need to see the module options:</p><p><code>show options</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Name       Current Setting  Required </span></span>
<span class="line"><span>----       ---------------  -------- </span></span>
<span class="line"><span>BATCHSIZE  256              yes      </span></span>
<span class="line"><span>DELAY      0                yes      </span></span>
<span class="line"><span>INTERFACE                   no       </span></span>
<span class="line"><span>JITTER     0                yes      </span></span>
<span class="line"><span>PORTS      1-10000          yes      </span></span>
<span class="line"><span>RHOSTS                      yes      </span></span>
<span class="line"><span>SNAPLEN    65535            yes      </span></span>
<span class="line"><span>THREADS    1                yes      </span></span>
<span class="line"><span>TIMEOUT    500              yes</span></span></code></pre></div><p>Set the <code>RHOSTS</code> to the target and <code>THREADS</code> to <code>100</code></p><p><code>set RHOSTS 10.0.2.23</code><code>set THREADS 100</code></p><p>Type <code>run</code> to launch the module.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[+]  TCP OPEN 10.0.2.23:53</span></span>
<span class="line"><span>[+]  TCP OPEN 10.0.2.23:80</span></span>
<span class="line"><span>[+]  TCP OPEN 10.0.2.23:88</span></span>
<span class="line"><span>[+]  TCP OPEN 10.0.2.23:135</span></span>
<span class="line"><span>[+]  TCP OPEN 10.0.2.23:139</span></span>
<span class="line"><span>[+]  TCP OPEN 10.0.2.23:389</span></span>
<span class="line"><span>[+]  TCP OPEN 10.0.2.23:443</span></span>
<span class="line"><span>[+]  TCP OPEN 10.0.2.23:445</span></span>
<span class="line"><span>[+]  TCP OPEN 10.0.2.23:464</span></span>
<span class="line"><span>[+]  TCP OPEN 10.0.2.23:593</span></span>
<span class="line"><span>[+]  TCP OPEN 10.0.2.23:636</span></span>
<span class="line"><span>...</span></span></code></pre></div><p>This module will enumerate every open TCP services using a raw SYN scan.</p><p>Next scan, let&#39;s find out the SMB version. Load the <strong>scanner/smb/smb_version</strong> module:</p><p><code>use scanner/smb/smb_version</code></p><p>Type <code>show options</code> to see the configuration.</p><p>Set the <code>RHOSTS</code> to the target and <code>THREADS</code> to <code>100</code></p><p><code>set RHOSTS 10.0.2.23</code><code>set THREADS 100</code></p><p>Type <code>run</code> to launch the module.</p><p>Now type <code>hosts</code> and observe the field <strong>os_flavor</strong> of the host you scanned in the subnet.</p><p>Conclusion: You can collect different error messages to learn the vulnerabilities, and note the information disclosed about the network.</p>`,67)]))}const m=s(o,[["render",p]]);export{u as __pageData,m as default};
